import React, { useEffect, useState } from "react";

const UploadBills = ({ employee }) => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [bills, setBills] = useState([]);

  useEffect(() => {
    if (employee?.empId || employee?.empld) {
      loadBills();
    }
  }, [employee]);

  const loadBills = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/bills?empId=${empId}`
      );

      const data = await response.json();

      if (Array.isArray(data)) setBills(data);
      else setBills([]);
    } catch (err) {
      console.error(err);
      setBills([]);
    }
  };

  const uploadBill = async () => {
    try {
      if (!selectedFile) {
        alert("Select a bill file first");
        return;
      }

      const formData = new FormData();
      const empId = employee.empId || employee.empld;

      formData.append("file", selectedFile);
      formData.append("empId", empId);

      const response = await fetch(
        "https://prasa-app-yde3.onrender.com/upload-bill",
        {
          method: "POST",
          body: formData,
        }
      );

      const data = await response.json();

      if (data.success) {
        alert("Bill uploaded!");
        loadBills();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const deleteBill = async (id) => {
    try {
      await fetch(`https://prasa-app-yde3.onrender.com/bills/${id}`, {
        method: "DELETE",
      });

      loadBills();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="history-container">
      <h2>Upload Bills</h2>

      <input type="file" onChange={(e) => setSelectedFile(e.target.files[0])} />

      <button className="save-btn" onClick={uploadBill}>
        Upload Bill
      </button>

      <table className="history-table">
        <thead>
          <tr>
            <th>Date</th>
            <th>File Name</th>
            <th>Preview</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {bills.length > 0 ? (
            bills.map((b) => (
              <tr key={b.id}>
                <td>{b.uploaded_at?.substring(0, 10)}</td>
                <td>{b.file_name}</td>
                <td>
                  <a
                    href={`https://prasa-app-yde3.onrender.com${b.file_path}`}
                    target="_blank"
                    rel="noreferrer"
                  >
                    View
                  </a>
                </td>
                <td>
                  <button className="delete-btn" onClick={() => deleteBill(b.id)}>
                    Delete
                  </button>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="4" style={{ textAlign: "center" }}>
                No bills uploaded yet
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default UploadBills;
